// Webhook数据可能在body字段中，需要解析JSON
const webhookData = items[0].json;
let inputData;

// 尝试从body字段解析JSON
if (webhookData.body) {
  try {
    if (typeof webhookData.body === 'string') {
      inputData = JSON.parse(webhookData.body);
    } else {
      inputData = webhookData.body;
    }
  } catch (error) {
    // 如果解析失败，使用原始数据
    inputData = webhookData.body;
  }
} else {
  // 如果没有body字段，使用整个webhook数据
  inputData = webhookData;
}

// 确保必要字段存在
const requiredFields = ['userName', 'userId', 'subscribers', 'followers', 'likes', 'allTitles', 'top10Notes'];
for (const field of requiredFields) {
  if (!inputData[field]) {
    inputData[field] = '';
  }
}

return [
  {
    json: {
      ...inputData,
      _originalData: inputData
    }
  }
];

// 从AI Agent的输出中提取数据
const aiOutput = items[0].json;

// 解析JSON输出
let parsedData;
try {
  if (typeof aiOutput === 'string') {
    parsedData = JSON.parse(aiOutput);
  } else {
    parsedData = aiOutput;
  }
} catch (error) {
  // 如果解析失败，尝试从可能的字段中提取
  parsedData = aiOutput;
}

// 确保数据格式正确
const authorData = parsedData.authorData || {};
const notesData = parsedData.notesData || [];
const report = parsedData.report || '';

// 获取原始输入数据以计算other_notes
const originalData = $('parse-input-1').item.json._originalData || {};
const allTitles = originalData.allTitles || [];
const top10Titles = notesData.map(note => note.title);
const otherNotes = allTitles.filter(title => !top10Titles.includes(title));

// 确保数字字段是整数
const cleanAuthorData = {
  user_name: String(authorData.user_name || originalData.userName || ''),
  user_xhs_id: String(authorData.user_xhs_id || originalData.userId || ''),
  subscribers: parseInt(authorData.subscribers || originalData.subscribers || 0),
  followers: parseInt(authorData.followers || originalData.followers || 0),
  likes: parseInt(authorData.likes || originalData.likes || 0),
  profile_url: null,
  other_notes: otherNotes,
  report: report
};

// 清理笔记数据
const cleanNotesData = notesData.map((note, index) => ({
  title: String(note.title || ''),
  description: String(note.description || ''),
  likes: parseInt(note.likes || 0),
  collects: parseInt(note.collects || 0),
  is_top10: true,
  raw_json: note.raw_json || note || {}
}));

return [
  {
    json: {
      authorData: cleanAuthorData,
      notesData: cleanNotesData,
      originalUserId: originalData.userId || ''
    }
  }
];

// 获取作者ID
const authorResult = $('get-author-id-1').item;
const authorId = authorResult && authorResult.json && authorResult.json.id ? authorResult.json.id : null;

if (!authorId) {
  throw new Error('未能获取作者ID，无法插入笔记数据');
}

// 获取笔记数据
const notesData = $('process-ai-output-1').item.json.notesData || [];

// 为每条笔记添加author_id
const notesWithAuthorId = notesData.map(note => ({
  ...note,
  author_id: authorId
}));

// 返回笔记数据数组
return notesWithAuthorId.map(note => ({
  json: note
}));

// 检查数据库操作是否成功
const authorInsertResult = $('insert-author-1').item;
const notesInsertResult = $('insert-notes-1').allItems;

const authorSuccess = !!authorInsertResult;
const notesSuccess = notesInsertResult && notesInsertResult.length > 0;
const notesCount = notesSuccess ? notesInsertResult.length : 0;

const success = authorSuccess && notesSuccess;

return [
  {
    json: {
      success: success,
      message: success ? "数据保存成功" : "数据保存失败",
      authorInserted: authorSuccess,
      notesInserted: notesCount,
      authorId: authorInsertResult ? authorInsertResult.json.id : null
    }
  }
];
